import{_ as o,c as i,o as l,ag as a}from"./chunks/framework.DVUBUV_u.js";const p=JSON.parse('{"title":"Release 2.3.0","description":"","frontmatter":{"title":"Release 2.3.0"},"headers":[],"relativePath":"releases/2.3.0.md","filePath":"releases/2.3.0.md"}'),t={name:"releases/2.3.0.md"};function r(c,e,d,s,n,h){return l(),i("div",null,[...e[0]||(e[0]=[a('<h2 id="_2-3-0-2026-03-16" tabindex="-1">[2.3.0] - 2026-03-16 <a class="header-anchor" href="#_2-3-0-2026-03-16" aria-label="Permalink to &quot;[2.3.0] - 2026-03-16&quot;">​</a></h2><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li><code>Postman</code> collection export from captured <code>Network</code> traffic.</li><li>Single-panel mode: <code>Copy cURL</code> replaced with a header context menu — <code>Breakpoint</code>, <code>Mock</code>, <code>Copy cURL</code>.</li><li>Right-click context menu on request detail header.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Favorites and blacklist behavior fixes.</li><li>Blacklist applied during collection traversal (not only table filtering) — faster Props load.</li><li>Quick actions menu for <code>Props</code>.</li><li>Refresh open component in read mode.</li><li>Shortcut jump to favorites from the favorites counter.</li></ul><hr><h3 id="store" tabindex="-1">Store <a class="header-anchor" href="#store" aria-label="Permalink to &quot;Store&quot;">​</a></h3><ul><li>Pinia <code>favorites</code> with shortcut navigation.</li><li>Quick actions menu for <code>Pinia Store</code>.</li><li>Refresh open entry in read mode.</li><li><code>Options</code> supports manual favorite entries with <code>wildcards</code>.</li></ul><hr><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><ul><li>User files now persist as local copies in app storage.</li><li><code>Standalone</code> uses dedicated local storage — settings survive relaunch and work across sites.</li><li>Tree JSON editor temporarily disabled — text mode only.</li></ul><h4 id="customize" tabindex="-1">Customize <a class="header-anchor" href="#customize" aria-label="Permalink to &quot;Customize&quot;">​</a></h4><p><code>Options → General → Customize</code> adds theming:</p><ul><li><code>Dark / Light</code> color scheme;</li><li><code>Image</code> background (<code>File / Link</code>) with stills, <code>GIF</code>, <code>MP4</code>;</li><li><code>Browse</code> or pick from saved files;</li><li>Add by URL;</li><li><code>Image Opacity</code>, <code>Blur</code>, <code>Noise Intensity / Opacity</code>, <code>Position (X / Y)</code>, <code>Scale</code> (<code>100–200%</code>).</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Responsive layout for smaller screens.</li><li>Wide layout: split list + details.</li><li>~<code>1000px</code> width collapses to single-panel.</li><li><code>Esc</code> closes panels/dialogs.</li><li><code>Ctrl+F</code> search in <code>DevTools</code> tab mode.</li><li>Loading skeletons for <code>Props</code> / <code>Pinia</code> tables instead of raw “Not found”.</li><li>Column visibility toggles for <code>Props</code>, <code>Pinia</code>, <code>Network</code>.</li><li>Chevron redesign for iframe open/close.</li><li>Table context menus (right-click).</li></ul><hr><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Blacklist applied during Props tree pre-walk — faster data collection and tab load.</li></ul><hr><h3 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li>JSON edit hit area while scrolling.</li><li><code>Network</code> tab freezes after long sessions.</li><li><code>Ctrl+A</code> selects only the focused input.</li><li>Reset/delete buttons respect <code>disabled</code> state.</li><li><code>Options</code> tables with many rows.</li><li>JSON edit mode styling.</li><li>Minor cosmetic fixes.</li></ul>',24)])])}const m=o(t,[["render",r]]);export{p as __pageData,m as default};
